@startuml
left to right direction
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

class "Project" {
  *C
}

class "User" {
  *C
}

class "Submission" {
  *C
}

class "Admin" {
  *C
}

class "Author" {
  *C
}

class "Revision" {
  *C
}

class "Editor" {
  *C
}

class "Resource" {
  *C
}

class "Document" {
  *C
}

class "AudioFile" {
  *C
}

class "Video" {
  *C
}

class "Comment" {
  *C
}

"Project" --o "User" : 1 *
"Project" --o "Submission" : 1 *
"Project" --o "Resource" : 1 1*

"User" <|-- "Admin"
"User" <|-- "Author"
"User" <|-- "Editor"

"Submission" --o "Author" : 1 1
"Submission" --o "Revision" : 1 1
"Submission" --o "Resource" : 1 1

"Revision" --o "Editor" : 1 1
"Revision" --o "Resource" : 1 1

"Author" --o "Comment" : 1 1*
"Editor" --o "Comment" : 1 1

"Resource" <|-- "Document"
"Resource" <|-- "AudioFile"
"Resource" <|-- "Video"

@enduml
